function toggleDropdown(dropdownId) {
    const contentId = dropdownId.replace('-dropdown', '-content');
    const chevronId = dropdownId.replace('-dropdown', '-chevron');
    const content = document.getElementById(contentId);
    const chevron = document.getElementById(chevronId);

    if (!content || !chevron) {
        return;
    }

    const isClosed = content.style.display === 'none' || content.style.display === '';
    content.style.display = isClosed ? 'block' : 'none';
    chevron.style.transform = isClosed ? 'rotate(180deg)' : 'rotate(0deg)';
}

document.addEventListener('DOMContentLoaded', function () {
    if (typeof Alpine === 'undefined' && window.sidebarConfig) {
        const currentPage = window.sidebarConfig.currentPage;
        const dropdownMap = {
            'incident-reports.php': 'report-dropdown',
            'maps.php': 'report-dropdown',
            'new-barangay-clearance.php': 'document-dropdown',
            'new-certificate-of-indigency.php': 'document-dropdown',
            'new-certificate-of-residency.php': 'document-dropdown',
            'user-management.php': 'admin-dropdown',
            'chat.php': 'admin-dropdown',
            'logs.php': 'admin-dropdown',
            'announcements.php': 'announcement-dropdown',
            'events.php': 'announcement-dropdown'
        };

        const activeDropdown = dropdownMap[currentPage];
        if (activeDropdown) {
            const dropdown = document.getElementById(activeDropdown);
            if (dropdown) {
                dropdown.classList.remove('hidden');
            }
        }
    }

    if (!window.sidebarConfig) {
        return;
    }

    const chatApiBase = window.sidebarConfig.apiBase;
    const notificationsBase = window.sidebarConfig.notifBase;

    const adminUnreadDot = document.getElementById('admin-unread-dot');
    const chatUnreadBadge = document.getElementById('chat-unread-badge');
    const reportUnreadDot = document.getElementById('report-unread-dot');
    const incidentBadge = document.getElementById('incident-reports-badge');
    const eventsUnreadDot = document.getElementById('events-unread-dot');
    const eventsBadge = document.getElementById('events-badge');

    function setBadge(el, count) {
        if (!el) return;
        if (count > 0) {
            el.textContent = count > 99 ? '99+' : String(count);
            el.style.display = 'inline-block';
        } else {
            el.style.display = 'none';
        }
    }

    function setDot(el, show) {
        if (!el) return;
        el.style.display = show ? 'inline-block' : 'none';
    }

    function refreshChatUnread() {
        fetch(chatApiBase + '?action=get_unread_count')
            .then(function (r) { return r.json(); })
            .then(function (data) {
                if (!data.success) return;
                const unread = data.unread || 0;
                setBadge(chatUnreadBadge, unread);
                setDot(adminUnreadDot, unread > 0);
            })
            .catch(function () {});
    }

    function refreshSidebarCounts() {
        fetch(notificationsBase + '?action=get_admin_sidebar_counts')
            .then(function (r) { return r.json(); })
            .then(function (data) {
                if (!data.success) return;
                const incidents = data.incidents || 0;
                const events = data.events || 0;
                setBadge(incidentBadge, incidents);
                setDot(reportUnreadDot, incidents > 0);
                setBadge(eventsBadge, events);
                setDot(eventsUnreadDot, events > 0);
            })
            .catch(function () {});
    }

    window.updateUnreadBadge = refreshChatUnread;

    refreshChatUnread();
    refreshSidebarCounts();

    setInterval(refreshChatUnread, 10000);
    setInterval(refreshSidebarCounts, 10000);
});
